INSERT INTO peliculas (titulo, descripcion, reparto, imagen) VALUES
('Stranger Things', 'A group of young friends witness supernatural forces and secret government exploits.', 'Millie Bobby Brown, Finn Wolfhard', '/assets/movies/49WJfeN0moxb9IPfGn8AIqMGskD.jpg'),
('The Witcher', 'Geralt of Rivia, a solitary monster hunter, struggles to find his place in a world.', 'Henry Cavill, Anya Chalotra', '/assets/movies/7vjaCdMw15FEbXyLQTVa04URsPm.jpg'),
('Wednesday', 'Smart, sarcastic and a little dead inside, Wednesday Addams investigates a murder spree.', 'Jenna Ortega, Gwendoline Christie', '/assets/movies/9PFonBhy4cQy7Jz20NpMygczOkv.jpg'),
('Squid Game', 'Hundreds of cash-strapped players accept a strange invitation to compete in children''s games.', 'Lee Jung-jae, Park Hae-soo', '/assets/movies/dDlEmu3EZ0Pgg93K2SVNLCjCSvE.jpg'),
('Ozark', 'A financial adviser drags his family from Chicago to the Missouri Ozarks, where he must launder money.', 'Jason Bateman, Laura Linney', '/assets/movies/ozark.svg'),
('Dark', 'A family saga with a supernatural twist, set in a German town where the disappearance of two young children exposes the relationships among four families.', 'Louis Hofmann, Lisa Vicari', '/assets/movies/apbrbWs8M9lyOpJYU5WXrpFbk1Z.jpg'),
('Money Heist', 'To carry out the biggest heist in history, a mysterious man called The Professor recruits a band of eight robbers who have a single characteristic: none of them has anything to lose.', 'Úrsula Corberó, Álvaro Morte', '/assets/movies/reEMJA1uzscCbkpeRJeTT2bjqUp.jpg'),
('Narcos', 'A gritty chronicle of the war against Colombia''s infamously violent and powerful drug cartels.', 'Wagner Moura, Pedro Pascal', '/assets/movies/rTmal9fDbwh5F0waol2hq35U4ah.jpg'),
('Black Mirror', 'An anthology series exploring a twisted, high-tech multiverse where humanity''s greatest innovations and darkest instincts collide.', 'Jesse Plemons, Cristin Milioti', '/assets/movies/7PRddO7z7mcPi21nZTCMGShAyy1.jpg'),
('Bridgerton', 'Wealth, lust, and betrayal set against the backdrop of Regency-era England, seen through the eyes of the powerful Bridgerton family.', 'Phoebe Dynevor, Regé-Jean Page', '/assets/movies/luoKpgVwi1E5nQsi7W0UuKHu2Rq.jpg');
